module frequency_divider(  
    input wire clk,  
    input wire reset,  
    output reg q  
);  

always @(posedge clk or posedge reset) begin  
    if (reset)  
        q <= 0;  
    else  
        q <= ~q;  
end  
  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        q <= 1;
      end
    end
  end

endmodule
